        shell.addEventListener('pointermove',event=>{if(!drag||drag.pointerId!==event.pointerId)return;const dx=event.clientX-drag.startX,dy=event.clientY-drag.startY;if(Math.hypot(dx,dy)>3)drag.moved=true;if(kind==='relations'){graphPan.x=drag.origin.x+dx;graphPan.y=drag.origin.y+dy;graphRuntime?.updateCamera()}else{mapPan.x=drag.origin.x+dx;mapPan.y=drag.origin.y+dy;mapRuntime?.updateCamera()}event.preventDefault()});
