    function openGraphAlignMenu(event){const menu=$('graphAlignMenu'),shell=$('relationShell');menu.hidden=false;$('graphAlignToggle').setAttribute('aria-expanded','true');if(event){const rect=shell.getBoundingClientRect();menu.style.left=`${Math.max(8,Math.min(rect.width-198,event.clientX-rect.left))}px`;menu.style.top=`${Math.max(8,Math.min(rect.height-250,event.clientY-rect.top))}px`}else{menu.style.left='128px';menu.style.top='52px'}}
    function closeGraphAlignMenu(){$('graphAlignMenu').hidden=true;$('graphAlignToggle').setAttribute('aria-expanded','false')}
    function alignGraphSelection(mode){if(!graphRuntime)return;const items=graphRuntime.nodes.filter(node=>graphSelection.has(node.name));if(items.length<2){toast('두 개 이상의 노드를 선택하세요');closeGraphAlignMenu();return}if(mode.startsWith('distribute')&&items.length<3){toast('간격 정렬에는 세 개 이상의 노드가 필요합니다');closeGraphAlignMenu();return}const xs=items.map(node=>node.x),ys=items.map(node=>node.y);if(mode==='left')items.forEach(node=>node.x=Math.min(...xs));else if(mode==='right')items.forEach(node=>node.x=Math.max(...xs));else if(mode==='center-x'){const center=xs.reduce((sum,value)=>sum+value,0)/xs.length;items.forEach(node=>node.x=center)}else if(mode==='top')items.forEach(node=>node.y=Math.min(...ys));else if(mode==='bottom')items.forEach(node=>node.y=Math.max(...ys));else if(mode==='center-y'){const center=ys.reduce((sum,value)=>sum+value,0)/ys.length;items.forEach(node=>node.y=center)}else if(mode==='distribute-x'){items.sort((a,b)=>a.x-b.x);const gap=(items.at(-1).x-items[0].x)/(items.length-1);items.forEach((node,index)=>node.x=items[0].x+gap*index)}else if(mode==='distribute-y'){items.sort((a,b)=>a.y-b.y);const gap=(items.at(-1).y-items[0].y)/(items.length-1);items.forEach((node,index)=>node.y=items[0].y+gap*index)}items.forEach(node=>{node.x=worldCoordinate(node.x);node.y=worldCoordinate(node.y);graphPositions[node.name]={x:Math.round(node.x),y:Math.round(node.y)}});saveGraphPositions();graphRuntime.updateGeometry();closeGraphAlignMenu();toast(`${items.length}개 노드를 정렬했습니다`)}
