      if(data.risks.length){const shown=(urgent.length?urgent:data.risks).slice(0,4);appendFeed(urgent.length?'caution':'warning',data.project_name,'risk analysis',urgent.length?urgent.length+'개의 우선 확인 신호':'검토 가능한 신호 '+data.risks.length+'개',urgent.length?'중요도가 높은 항목부터 확인하세요.':'자동 분석에서 발견된 신호입니다.',[[data.risks.length,' signals'],[s.critical_risks,' critical']],shown.map(item=>({marker:el('span','severity-dot '+item.severity),title:item.title,detail:item.detail,meta:item.severity})))}
